import React, { useState, useMemo } from 'react';
import { ViewState, MenuCategory, CartItem, OverlayType } from '../types';
import { THEME, UI_CLASSES } from '../theme';
import { Icon } from '../icons';
import { Button, Card, Modal, Badge, Input } from '../components/UI';

interface POSHomeViewProps {
  onLogout: () => void;
  onNavigate: (view: ViewState) => void;
}

const POSHomeView: React.FC<POSHomeViewProps> = ({ onLogout, onNavigate }) => {
  const [activeMenu, setActiveMenu] = useState<MenuCategory>(MenuCategory.FUEL);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedPump, setSelectedPump] = useState<number>(1);
  const [overlay, setOverlay] = useState<OverlayType | null>(null);
  const [inputBuffer, setInputBuffer] = useState('');
  const [selectedRow, setSelectedRow] = useState<string | null>(null);

  const total = useMemo(() => cart.reduce((sum, item) => sum + item.total, 0), [cart]);

  const addToCart = (item: Partial<CartItem>) => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: item.name || 'Unknown Item',
      quantity: item.quantity || 1,
      price: item.price || 0,
      total: (item.price || 0) * (item.quantity || 1),
      isFuel: item.isFuel,
      pumpNo: item.isFuel ? selectedPump : undefined
    };
    setCart(prev => [...prev, newItem]);
    setSelectedRow(newItem.id);
  };

  const clearCart = () => setCart([]);
  const closeOverlay = () => { setOverlay(null); setInputBuffer(''); };

  const handleKeypad = (key: string | number) => {
    if (typeof key === 'number' || key === '00' || key === '.') {
      setInputBuffer(prev => {
        if (key === '.' && prev.includes('.')) return prev;
        return prev + key.toString();
      });
    } else if (key === 'BACK') {
      setInputBuffer(prev => prev.slice(0, -1));
    } else if (key === 'ENTER') {
       // Logic to apply buffer (e.g. as price or qty) could go here
       setInputBuffer('');
    } else if (key === 'CLEAR') {
       setInputBuffer('');
    }
  };

  const fuelProducts = [
    { name: '92# Gasoline', price: 6.77, color: 'bg-red-500' },
    { name: '95# Gasoline', price: 7.23, color: 'bg-green-500' },
    { name: '0# Diesel', price: 6.41, color: 'bg-slate-700' },
    { name: '98# Gasoline', price: 8.12, color: 'bg-blue-500' },
  ];

  // Specific styles for the grid layout
  const gridButtonBase = `relative flex flex-col items-center justify-center ${THEME.radius.base} shadow-sm border border-slate-200 transition-all active:translate-y-0.5 select-none`;
  const gridButtonDefault = `${gridButtonBase} ${THEME.colors.gradients.buttonDefault} text-slate-700 hover:border-blue-300`;
  const gridButtonAction = `${gridButtonBase} ${THEME.colors.gradients.buttonDefault} text-${THEME.colors.primary} font-bold hover:border-blue-400`;
  const gridButtonYellow = `${gridButtonBase} ${THEME.colors.gradients.buttonYellow} border-amber-300`;
  const gridButtonGray = `${gridButtonBase} ${THEME.colors.gradients.buttonGray} border-slate-300`;
  const gridButtonBlue = `${gridButtonBase} ${THEME.colors.gradients.buttonBlue} border-blue-600`;

  return (
    <div className={`flex h-screen w-screen bg-[#F0F2F5] p-2 gap-2 overflow-hidden`}>

      {/* LEFT PANEL: Cart & Pump Selection */}
      <div className="w-[42%] flex flex-col gap-2 h-full">
        {/* Header Total */}
        <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-4 flex justify-between items-center h-20 shrink-0">
           <span className="text-xl font-bold text-slate-700">Total</span>
           <span className={`text-5xl ${THEME.typography.heading} text-slate-900`}>{total.toFixed(2)}</span>
        </div>

        {/* Cart Table */}
        <div className="flex-1 bg-white rounded-lg shadow-sm border border-slate-200 flex flex-col overflow-hidden relative">
           {/* Table Header */}
           <div className="flex bg-[#F8FAFC] border-b border-slate-200 py-3 px-4 text-sm font-bold text-slate-500">
              <div className="flex-[3]">Name</div>
              <div className="flex-1 text-center">Qty</div>
              <div className="flex-1 text-right">Price</div>
              <div className="flex-1 text-right">Total</div>
           </div>

           {/* Table Body */}
           <div className="flex-1 overflow-y-auto custom-scrollbar p-0">
             {cart.length === 0 ? (
                <div className="h-full flex items-center justify-center text-slate-300 flex-col gap-2">
                   <Icon.Cart className="w-12 h-12 opacity-50" />
                   <p>Cart is empty</p>
                </div>
             ) : (
                cart.map((item) => (
                  <div 
                    key={item.id}
                    onClick={() => setSelectedRow(item.id)}
                    className={`flex py-3 px-4 border-b border-slate-100 items-center cursor-pointer transition-colors ${selectedRow === item.id ? 'bg-blue-50/80' : 'hover:bg-slate-50'}`}
                  >
                    <div className="flex-[3] font-bold text-slate-800 flex items-center gap-2">
                      {item.isFuel && (
                        <span className="w-5 h-5 rounded bg-blue-100 text-blue-600 flex items-center justify-center text-xs">
                          <Icon.Fuel size={12} />
                        </span>
                      )}
                      {item.name}
                    </div>
                    <div className="flex-1 text-center font-medium text-slate-600">{item.quantity}</div>
                    <div className="flex-1 text-right font-medium text-slate-600">{item.price.toFixed(2)}</div>
                    <div className="flex-1 text-right font-bold text-slate-900">{item.total.toFixed(2)}</div>
                  </div>
                ))
             )}
             {/* Selected Row Highlight Visual Placeholder (mimicking the grey bar in reference if list is empty) */}
             {cart.length === 0 && (
                 <div className="absolute top-1/2 left-0 w-full h-12 bg-slate-100/50 -translate-y-1/2 pointer-events-none border-y border-slate-200/50"></div>
             )}
           </div>
        </div>

        {/* Bottom Pump Area */}
        <div className="shrink-0 h-48 flex flex-col gap-2">
           {/* Yellow Pump Bar */}
           <div className={`h-14 ${THEME.colors.gradients.barYellow} rounded-lg shadow-sm border border-amber-300 flex items-center justify-between px-6`}>
              <button 
                onClick={() => setSelectedPump(p => p > 1 ? p - 1 : 4)}
                className="p-2 bg-white/30 rounded-full hover:bg-white/50 text-amber-900"
              >
                 <Icon.Reset className="w-6 h-6 rotate-180" />
              </button>
              <div className="text-2xl font-black text-amber-900 uppercase tracking-tight flex items-center gap-2">
                 Pump {selectedPump}
              </div>
              <button 
                 onClick={() => setSelectedPump(p => p < 4 ? p + 1 : 1)}
                 className="p-2 bg-white/30 rounded-full hover:bg-white/50 text-amber-900"
              >
                 <Icon.ChevronRight className="w-8 h-8" />
              </button>
           </div>

           {/* Nozzle/Product Buttons */}
           <div className="flex-1 grid grid-cols-4 gap-2">
              {fuelProducts.map((fuel, idx) => (
                 <button 
                    key={idx}
                    onClick={() => addToCart({...fuel, isFuel: true})}
                    className={`${gridButtonBlue} !border-0 shadow-md relative overflow-hidden group`}
                    style={{ background: 'linear-gradient(to bottom, #3b82f6, #1d4ed8)' }}
                 >
                    <div className="absolute top-2 right-2 opacity-20 group-hover:opacity-40 transition-opacity">
                       <Icon.Fuel className="w-12 h-12" />
                    </div>
                    <div className="text-3xl font-black text-white drop-shadow-md z-10">{idx + 1}</div>
                    <div className="text-xs font-bold text-blue-100 uppercase mt-1 z-10">{fuel.name.split(' ')[0]}</div>
                 </button>
              ))}
           </div>
        </div>
      </div>

      {/* RIGHT PANEL: Grid Interface */}
      <div className="flex-1 flex flex-col gap-2 h-full">
         {/* Top Status Bar */}
         <div className={`h-10 rounded-lg ${THEME.colors.gradients.buttonDefault} border border-slate-200 flex items-center px-4 justify-between shadow-sm`}>
             <div className="flex items-center gap-2 text-slate-600 text-sm font-bold">
                <Icon.Success className="w-4 h-4 text-blue-500" />
                <span>Ready: {fuelProducts[0].name} selected</span>
             </div>
             <Icon.Globe className="w-4 h-4 text-slate-400" />
         </div>

         {/* Main 6x7 Grid */}
         <div className="flex-1 grid grid-cols-6 grid-rows-[0.8fr_1fr_1fr_1fr_1fr_1fr_1.2fr] gap-2">

            {/* ROW 1: Categories / Tabs */}
            {[
               { icon: Icon.Fuel, label: 'Oil' },
               { icon: Icon.Cart, label: 'Goods' },
               { icon: Icon.Keypad, label: 'Number' },
               { icon: Icon.Payment, label: 'Pay' },
               { icon: Icon.Analytics, label: 'Data' },
               { icon: Icon.Settings, label: 'System' }
            ].map((menu, i) => (
               <button 
                  key={i} 
                  onClick={() => i === 1 ? setOverlay(OverlayType.PRODUCT_LOOKUP) : null}
                  className={`${gridButtonDefault} bg-white`}
               >
                  <menu.icon className="w-5 h-5 mb-1 text-slate-500" />
                  <span className="text-xs font-bold text-slate-600">{menu.label}</span>
               </button>
            ))}

            {/* ROW 2 */}
            <button onClick={() => setOverlay(OverlayType.REPRINT_RECEIPT)} className={gridButtonDefault}><span className="text-xs font-bold">Reprint</span></button>
            <button onClick={() => setOverlay(OverlayType.HOLD_ORDER)} className={gridButtonDefault}><span className="text-xs font-bold">Hold</span></button>
            <button onClick={() => handleKeypad(7)} className={gridButtonDefault}><span className="text-xl font-bold">7</span></button>
            <button onClick={() => handleKeypad(8)} className={gridButtonDefault}><span className="text-xl font-bold">8</span></button>
            <button onClick={() => handleKeypad(9)} className={gridButtonDefault}><span className="text-xl font-bold">9</span></button>
            <button className={gridButtonAction}><span className="text-sm font-bold">Qty</span></button>

            {/* ROW 3 */}
            <button onClick={() => setOverlay(OverlayType.TEMP_PRICE)} className={gridButtonDefault}><span className="text-xs font-bold leading-tight">Price<br/>Chg</span></button>
            <button 
               onClick={() => {
                  if(selectedRow) setCart(c => c.filter(x => x.id !== selectedRow));
                  else if(cart.length > 0) setCart(c => c.slice(0, -1));
               }} 
               className={gridButtonDefault}
            >
               <span className="text-xs font-bold">Delete</span>
            </button>
            <button onClick={() => handleKeypad(4)} className={gridButtonDefault}><span className="text-xl font-bold">4</span></button>
            <button onClick={() => handleKeypad(5)} className={gridButtonDefault}><span className="text-xl font-bold">5</span></button>
            <button onClick={() => handleKeypad(6)} className={gridButtonDefault}><span className="text-xl font-bold">6</span></button>
            <button className={gridButtonAction}><span className="text-sm font-bold">Amt</span></button>

            {/* ROW 4 */}
            <button className={gridButtonDefault}><span className="text-xs font-bold">NoTax</span></button>
            <button onClick={() => setOverlay(OverlayType.SPECIAL_DISCOUNT)} className={gridButtonDefault}><span className="text-xs font-bold">Disc.</span></button>
            <button onClick={() => handleKeypad(1)} className={gridButtonDefault}><span className="text-xl font-bold">1</span></button>
            <button onClick={() => handleKeypad(2)} className={gridButtonDefault}><span className="text-xl font-bold">2</span></button>
            <button onClick={() => handleKeypad(3)} className={gridButtonDefault}><span className="text-xl font-bold">3</span></button>
            <button onClick={() => setOverlay(OverlayType.PRODUCT_LOOKUP)} className={gridButtonAction}><span className="text-sm font-bold">Items</span></button>

            {/* ROW 5 */}
            <button className={gridButtonDefault}><span className="text-xs font-bold leading-tight">Pre<br/>Tax</span></button>
            <button className={`${gridButtonDefault} bg-slate-50 opacity-50`}></button>
            <button onClick={() => handleKeypad('00')} className={gridButtonDefault}><span className="text-xl font-bold">00</span></button>
            <button onClick={() => handleKeypad(0)} className={gridButtonDefault}><span className="text-xl font-bold">0</span></button>
            <button onClick={() => handleKeypad('.')} className={gridButtonDefault}><span className="text-xl font-bold">.</span></button>
            <button onClick={() => handleKeypad('ENTER')} className={gridButtonAction}><span className="text-sm font-bold">Enter</span></button>

            {/* ROW 6 */}
            <button className={gridButtonDefault}><span className="text-xs font-bold">Memb.</span></button>
            <button className={gridButtonDefault}><span className="text-xs font-bold">Fleet</span></button>
            <button className={gridButtonDefault}><Icon.Keyboard className="w-5 h-5" /></button>
            <button className={gridButtonDefault}><span className="text-xs font-bold">Space</span></button>
            <button onClick={() => handleKeypad('BACK')} className={gridButtonDefault}><Icon.Backspace className="w-5 h-5" /></button>
            <button onClick={clearCart} className={`${gridButtonDefault} text-red-500 hover:text-red-600`}><span className="text-xs font-bold">Cancel</span></button>

            {/* ROW 7 (BOTTOM ACTIONS) */}
            <button onClick={() => setOverlay(OverlayType.MEMBER_CHECK)} className={gridButtonYellow}>
               <Icon.User className="w-6 h-6 mb-1 opacity-80" />
               <span className="text-xs font-black">Account</span>
            </button>
            <button onClick={() => setOverlay(OverlayType.VOUCHER_SCAN)} className={gridButtonYellow}>
               <Icon.Voucher className="w-6 h-6 mb-1 opacity-80" />
               <span className="text-xs font-black">Voucher</span>
            </button>
            <button onClick={() => setOverlay(OverlayType.LAKALA_SCAN)} className={gridButtonGray}>
               <Icon.Scan className="w-6 h-6 mb-1 opacity-60" />
               <span className="text-xs font-black">Lakala</span>
            </button>
            <button onClick={() => setOverlay(OverlayType.SETTLEMENT_CONFIRM)} className={gridButtonGray}>
               <Icon.Cash className="w-6 h-6 mb-1 opacity-60" />
               <span className="text-xs font-black">Cash</span>
            </button>
            <button onClick={() => setOverlay(OverlayType.SETTLEMENT_CONFIRM)} className={`${gridButtonBlue} col-span-2 text-2xl`}>
               <span className="font-black">Total</span>
            </button>
         </div>

         {/* Footer Info */}
         <div className="h-8 flex justify-between items-center px-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider">
             <div className="flex gap-4">
               <span>DEV: T202192G40579</span>
               <span>VER: 3.2.0</span>
             </div>
             <div className="flex gap-4">
               <span className="flex items-center gap-1"><Icon.User size={10} /> Luo Yun</span>
               <span>2026-01-23 14:05</span>
             </div>
         </div>
      </div>

      {/* --- OVERLAYS --- */}

      <Modal isOpen={overlay === OverlayType.PRODUCT_LOOKUP} onClose={closeOverlay} title="Select Product">
         <div className="grid grid-cols-4 gap-4">
            {[...fuelProducts, {name: 'Motor Oil', price: 15}, {name: 'Water', price: 2}, {name: 'Snacks', price: 5}, {name: 'Coffee', price: 3}].map((p: any, idx) => (
               <button 
                  key={idx} 
                  onClick={() => { addToCart(p); closeOverlay(); }}
                  className="aspect-square bg-slate-50 hover:bg-blue-50 border border-slate-200 hover:border-blue-300 rounded-lg flex flex-col items-center justify-center p-2 transition-colors"
               >
                  <span className="font-bold text-slate-800 text-center text-sm">{p.name}</span>
                  <span className="text-xs text-slate-500 mt-1">${p.price.toFixed(2)}</span>
               </button>
            ))}
         </div>
      </Modal>

      <Modal isOpen={overlay === OverlayType.SETTLEMENT_CONFIRM} onClose={closeOverlay} title="Payment">
         <div className="space-y-6 text-center">
            <h2 className="text-4xl font-black text-slate-800">${total.toFixed(2)}</h2>
            <div className="grid grid-cols-2 gap-4">
               <Button onClick={() => { setOverlay(OverlayType.PAYMENT_SUCCESS); }} className="h-16 text-lg" icon={Icon.Payment}>Confirm Pay</Button>
               <Button onClick={closeOverlay} variant="outline" className="h-16 text-lg">Cancel</Button>
            </div>
         </div>
      </Modal>

      <Modal isOpen={overlay === OverlayType.PAYMENT_SUCCESS} onClose={() => { clearCart(); closeOverlay(); }} title="Success">
         <div className="text-center py-8">
            <Icon.Success className="w-20 h-20 text-green-500 mx-auto mb-4" />
            <h2 className="text-2xl font-bold text-slate-800">Transaction Complete</h2>
            <p className="text-slate-500 mt-2">Receipt has been queued for printing.</p>
            <Button onClick={() => { clearCart(); closeOverlay(); }} className="mt-8 w-full">Start New Order</Button>
         </div>
      </Modal>

       {/* Generic placeholders for new buttons */}
       {[OverlayType.HOLD_ORDER, OverlayType.TEMP_PRICE, OverlayType.SPECIAL_DISCOUNT, OverlayType.REPRINT_RECEIPT].map(type => (
          <Modal key={type} isOpen={overlay === type} onClose={closeOverlay} title={type.replace('_', ' ')}>
             <div className="text-center py-8 space-y-4">
                <p className="text-slate-500">Functionality for {type} would be implemented here.</p>
                <Button onClick={closeOverlay}>Close</Button>
             </div>
          </Modal>
       ))}

       <Modal isOpen={overlay === OverlayType.LAKALA_SCAN || overlay === OverlayType.VOUCHER_SCAN} onClose={closeOverlay} title="Scan">
